SELECT , CASE WHEN #{viewerId,jdbcType=BIGINT} IS NULL THEN FALSE ELSE EXISTS ( SELECT 1 FROM favorites f WHERE f.user_id = #{viewerId,jdbcType=BIGINT} AND f.gym_id = gyms.id ) END AS favorite FROM gyms WHERE status = 'active' AND deleted_at IS NULL
AND name ILIKE '%' || #{keyword} || '%' ESCAPE '\'
AND region_code = #{region}
ORDER BY favorite DESC, name, id LIMIT #{size} OFFSET #{offset}

